// mm/src/api/listDocuments.js
import axios from 'axios';
import { withAuthRetry, refreshTokens } from './refresh';


const DEFAULT_API_BASE = 'https://manuscriptmagic.fowkes.xyz/services';
const API_BASE = process.env.REACT_APP_API_BASE_URL || DEFAULT_API_BASE;

const ACCESS_KEY = 'mm_accessToken';
const ACCESS_CREATED_KEY = 'mm_accessTokenCreatedAt';

const FIFTEEN_MINUTES = 15 * 60 * 1000;

export async function getAccessToken() {
  const token = localStorage.getItem(ACCESS_KEY);
  const createdAt = localStorage.getItem(ACCESS_CREATED_KEY);

  if (!token || !createdAt) {
    return '';
  }

  const tokenAge = Date.now() - Number(createdAt);

  // If older than 15 minutes → refresh
  if (tokenAge > FIFTEEN_MINUTES) {
    try {
      console.log('Access token older than 15 minutes. Refreshing...');

      const refreshResponse = await refreshTokens();

      const newAccessToken = refreshResponse?.accessToken;

      if (newAccessToken) {
        localStorage.setItem(ACCESS_KEY, newAccessToken);
        localStorage.setItem(ACCESS_CREATED_KEY, Date.now().toString());

        console.log('Token refreshed successfully');

        return newAccessToken;
      }

      console.error('refreshTokens did not return accessToken');
      return '';

    } catch (err) {
      console.error('Token refresh failed:', err);
      return '';
    }
  }

  return token;
}

/**
 * Normalize backend document object
 * Backend returns:
 *   - DocumentId
 *   - OrigionalFileName
 *   - FileSize
 */
function normalizeDocument(raw = {}) {
  return {
    documentId: raw.DocumentId || null,
    filename: raw.OrigionalFileName || null,
    size: raw.FileSize ?? null, // bytes
  };
}

/**
 * List all documents for the authenticated user
 *
 * Endpoint: listDocuments.php
 * Requires:
 *   - Authorization: Bearer <token>
 *   - accessToken (query param for PHP)
 *
 * Backend returns:
 *   [
 *     { DocumentId, OrigionalFileName, FileSize }
 *   ]
 *
 * Returns:
 *   Success: { success: true, data: { documents: [] }, status }
 *   Failure: { success: false, error, status }
 */
export async function listDocuments() {
  const accessToken = await getAccessToken();
  const url = `${API_BASE}/listDocuments.php`;

  if (!accessToken) {
    return {
      success: false,
      error: 'Missing access token',
      status: null,
    };
  }

  try {
    const response = await withAuthRetry(() =>
      axios.get(url, {
        headers: {
          Authorization: `Bearer ${accessToken}`,
          Accept: 'application/json',
        },
        params: { accessToken },
      })
    );

    // Backend returns array directly
    const rawDocs = Array.isArray(response.data) ? response.data : [];

    const documents = rawDocs.map(normalizeDocument);

    console.log('listDocuments success:', {
      status: response.status,
      count: documents.length,
      documents,
    });

    return {
      success: true,
      data: {
        documents,
      },
      status: response.status,
    };
  } catch (err) {
    const status = err?.response?.status ?? null;
    const backendError = err?.response?.data ?? null;
    const error = backendError || err?.message || 'Failed to list documents';

    console.error('listDocuments failed:', { status, error });

    return {
      success: false,
      error,
      status,
    };
  }
}
